import{_ as t,o as a,c as r,a7 as n}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"Gacha / Summoning","description":"","frontmatter":{},"headers":[],"relativePath":"en/modes/gacha.md","filePath":"en/modes/gacha.md","lastUpdated":1775394001000}'),i={name:"en/modes/gacha.md"};function d(s,e,l,o,h,u){return a(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="gacha-summoning" tabindex="-1">Gacha / Summoning <a class="header-anchor" href="#gacha-summoning" aria-label="Permalink to &quot;Gacha / Summoning&quot;">​</a></h1><p>The gacha system is how players obtain new Awakeners, Wheels of Destiny, and other items in Morimens. The game features a relatively generous SSR rate and a low pity threshold.</p><h2 id="pull-rates" tabindex="-1">Pull Rates <a class="header-anchor" href="#pull-rates" aria-label="Permalink to &quot;Pull Rates&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Rarity</th><th>Rate</th></tr></thead><tbody><tr><td><span class="rarity-ssr">SSR</span></td><td><strong>3%</strong> (increased from 1.02% in v2.0)</td></tr><tr><td><span class="rarity-sr">SR</span></td><td>Guaranteed 1 SR or higher every 5 pulls</td></tr><tr><td>On-Banner Rate</td><td>33.33% chance to be the featured UP character/wheel when pulling an SSR</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The SSR rate was <strong>increased from 1.02% to 3%</strong> in v2.0, making Morimens one of the more generous gacha games on the market.</p></div><h2 id="pity-system" tabindex="-1">Pity System <a class="header-anchor" href="#pity-system" aria-label="Permalink to &quot;Pity System&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pity Type</th><th>Threshold</th><th>Details</th></tr></thead><tbody><tr><td>Small Pity</td><td><strong>30 pulls</strong></td><td>Guaranteed SSR within 30 pulls (reduced from 80 in v2.0)</td></tr><tr><td>Escalating Guarantee</td><td>1st SSR: 33.33% UP / 2nd: 66.66% UP / 3rd: 100% UP</td><td>If you miss the featured character, odds improve with each SSR</td></tr><tr><td>Big Pity</td><td><strong>120 pulls</strong></td><td>Within 4 small pity cycles, guaranteed to obtain the UP character</td></tr><tr><td>Anti-Duplicate</td><td>After 2 consecutive same UP items</td><td>Next UP is guaranteed to be the other UP item</td></tr><tr><td>Cross-Banner</td><td>Independent</td><td>Limited and standard banner pity counters are tracked separately</td></tr></tbody></table><h2 id="banner-types" tabindex="-1">Banner Types <a class="header-anchor" href="#banner-types" aria-label="Permalink to &quot;Banner Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Banner</th><th>Currency</th><th>Description</th></tr></thead><tbody><tr><td>The Unforgotten (Standard)</td><td>Pure Core</td><td>Standard SSR pool. No UP mechanic. Every 30 pulls guarantees SSR. 5 awakenings guarantee SSR + wheel.</td></tr><tr><td>Obsidian Wings (Limited Debut)</td><td>Luminous Core</td><td>New limited character debut banner. Limited SSR do not enter standard pool.</td></tr><tr><td>Kaleido Recollections</td><td>Luminous Core</td><td>Pure limited pool (no standard SSR). 30-pull guarantee for limited SSR character or wheel. Good for new players to expand limited roster.</td></tr><tr><td>Rerun Banner</td><td>Luminous Core</td><td>Past limited character rerun banners.</td></tr><tr><td>Guaranteed Awakening</td><td>Silver Prime x980/pull</td><td>5 pulls guarantee 2 random limited SSR characters + 3 random limited SSR wheels. Split by arc (Oblivion/Stellar) and gender.</td></tr><tr><td>Self-Select Awakening</td><td>Varies</td><td>Event limited pool where you choose 1 SSR character + signature wheel as UP target.</td></tr></tbody></table><h2 id="summoning-currency" tabindex="-1">Summoning Currency <a class="header-anchor" href="#summoning-currency" aria-label="Permalink to &quot;Summoning Currency&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Currency</th><th>Type</th><th>How to Obtain</th></tr></thead><tbody><tr><td>Silver Prime</td><td>Paid premium</td><td>Real-money purchase</td></tr><tr><td>Silver (Silver Core)</td><td>Free premium (~200 Silver = 1 pull)</td><td>Daily tasks, main story scores (100/stage), main story achievements, handbook, Phantasmal Dive, events, battle pass, redemption codes, map exploration</td></tr><tr><td>Luminous Core</td><td>Limited banner (1 = 1 pull)</td><td>Silver exchange, events, battle pass. <strong>Priority exchange recommended.</strong></td></tr><tr><td>Pure Core</td><td>Standard banner (1 = 1 pull)</td><td>Silver exchange, events, first ascension reward, battle pass free track (40x), chapter first clear</td></tr><tr><td>Sediment Currency</td><td>Gacha byproduct</td><td>Generated as a byproduct when summoning</td></tr></tbody></table><h2 id="beginner-rewards" tabindex="-1">Beginner Rewards <a class="header-anchor" href="#beginner-rewards" aria-label="Permalink to &quot;Beginner Rewards&quot;">​</a></h2><p>New players receive generous summoning resources:</p><ul><li>1,500 Silver on launch (~7 pulls) + 15 standard pulls</li><li>7-day cumulative login: 10 additional event pool pulls</li><li>Reach Lv35: up to 40 standard pulls + 2,000 Silver (10 pulls)</li><li>3-day and 7-day login: 1 standard self-select SSR each</li><li>50 total pulls achievement: 1 standard self-select SSR</li><li>After 7 days: at least 3+ SSR characters guaranteed</li><li>Weekly rotation event: first 5 pulls free (up to 20 free pulls during event)</li></ul><h2 id="summoning-advice" tabindex="-1">Summoning Advice <a class="header-anchor" href="#summoning-advice" aria-label="Permalink to &quot;Summoning Advice&quot;">​</a></h2><ol><li><strong>Save for limited banners</strong> -- Limited Awakeners are only available during their banner period.</li><li><strong>Use Pure Core on standard pool first</strong> -- Only spend gifted Pure Cores; save Silver and Luminous Core for limited banners.</li><li><strong>Plan around pity</strong> -- With a 30-pull pity, budget your pulls to guarantee at least one SSR per banner you target.</li><li><strong>Priority targets for F2P</strong>: 24 first, then Murphy.</li><li><strong>Duplicates have value</strong> -- Duplicate Awakeners feed into the <a href="./../awakeners/enlightenment.html">Enlightenment</a> system, granting up to 5 levels of power boosts.</li><li><strong>Wheels matter</strong> -- An Awakener&#39;s signature <a href="./../wheels/">Wheel of Destiny</a> significantly boosts their power. Consider pulling for both.</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The standard banner is less efficient for targeting specific characters. Spend your premium currency on limited banners for the Awakeners you want most. Limited banner pity does not carry over to standard banner and vice versa.</p></div><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./../awakeners/list.html">Awakener List</a></li><li><a href="./../awakeners/enlightenment.html">Enlightenment</a></li><li><a href="./../wheels/">Wheels of Destiny</a></li><li><a href="./../items/currency.html">Currency</a></li></ul>',19)])])}const p=t(i,[["render",d]]);export{m as __pageData,p as default};
